package day02;

public class AssignmentOperatorPractice {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		// Ex1
		int a = 10;
		System.out.println("Value of a before: " + a);
		a += 10;
		System.out.println("Value of a after: " + a);

		// Ex2
		int b = 200;
		System.out.println("Value of b before: " + b);
		b -= 50;
		System.out.println("Value of b after: " + b);

		// Ex3
		int c = 25;
		System.out.println("Value of c before: " + c);
		c *= 10;
		System.out.println("Value of c after: " + c);

		// Ex4
		int d = 500;
		System.out.println("Value of d before: " + d);
		d /= 50;
		System.out.println("Value of d after: " + d);

	}

}
